class Solution:
    def maxPoints(self, points):
        m = len(points)
        n = len(points[0])
        dp = list(points[0])
        for r in range(1, m):
            ndp = [0] * n
            for c in range(n):
                best = float('-inf')
                for pc in range(n):
                    best = max(best, dp[pc] - abs(pc - c))
                ndp[c] = best + points[r][c]
            dp = ndp
        return max(dp)

