class Solution:
    def maxPoints(self, points):
        n = len(points[0])
        dp = list(points[0])
        for r in range(1, len(points)):
            left = [0] * n
            right = [0] * n
            left[0] = dp[0]
            for c in range(1, n):
                left[c] = max(left[c - 1] - 1, dp[c])
            right[n - 1] = dp[n - 1]
            for c in range(n - 2, -1, -1):
                right[c] = max(right[c + 1] - 1, dp[c])
            ndp = [0] * n
            for c in range(n):
                ndp[c] = points[r][c] + max(left[c], right[c])
            dp = ndp
        return max(dp)

