var maxPoints = function(points) {
    const n = points[0].length;
    let dp = points[0].slice();
    for (let r = 1; r < points.length; r++) {
        const left = new Array(n), right = new Array(n);
        left[0] = dp[0];
        for (let c = 1; c < n; c++) left[c] = Math.max(left[c - 1] - 1, dp[c]);
        right[n - 1] = dp[n - 1];
        for (let c = n - 2; c >= 0; c--) right[c] = Math.max(right[c + 1] - 1, dp[c]);
        const ndp = new Array(n);
        for (let c = 0; c < n; c++) ndp[c] = points[r][c] + Math.max(left[c], right[c]);
        dp = ndp;
    }
    return Math.max(...dp);
};
